// 产 SVG 字符串,零全局足迹;挂载载体差异见 note
import { toSVG } from 'https://cdn.jsdelivr.net/npm/bwip-js@4.11.2/+esm';
const svg = toSVG({
  bcid: data.bcid,
  text: data.text,
  scale: data.scale ?? 2,
  height: data.height,
  includetext: data.includetext ?? false,
  rotate: data.rotate ?? 'N'
});
// 挂载:widget → 落 shadowRoot;artifact/codex → 落目标容器
const holder = document.createElement('div');
holder.innerHTML = svg;
// widget: shadowRoot.appendChild(holder);  artifact/codex: targetEl.appendChild(holder);
